#include <stdio.h>

// This is a comment - a token type (not compiled)
// Keywords: int, float, char, return, void
// Identifiers: main, age, price, grade, printf

int main() {
    // Variable declarations (identifiers)
    int age = 25;           // Integer data type
    float price = 19.99;    // Floating-point data type
    char grade = 'A';       // Character data type

    // Using printf to display variables (format specifiers are tokens)
    printf("Student Age: %d\n", age);
    printf("Book Price: %.2f\n", price);
    printf("Grade: %c\n", grade);

    return 0;
}

#include <stdio.h>

#define PI 3.14159  // Macro token - constant (no memory allocation)

int main() {
    // Implicit type casting (integer promotion)
    int num1 = 10;
    int num2 = 3;
    float result = num1 / num2;  // Integer division, implicit cast to float
    printf("Implicit cast: 10/3 = %f\n", result);

    // Explicit type casting (forceful conversion)
    float explicitResult = (float)num1 / num2;
    printf("Explicit cast: (float)10/3 = %f\n", explicitResult);

    // Constant variable using const keyword
    const int MAX_SIZE = 100;
    // MAX_SIZE = 200; // Error: cannot modify const variable
    printf("Constant MAX_SIZE: %d\n", MAX_SIZE);

    // Using sizeof to check memory sizes (tokens: sizeof operator)
    printf("\nData Type Sizes:\n");
    printf("int: %zu bytes\n", sizeof(int));
    printf("float: %zu bytes\n", sizeof(float));
    printf("char: %zu bytes\n", sizeof(char));
    printf("double: %zu bytes\n", sizeof(double));

    printf("\nMacro PI: %.5f\n", PI);

    return 0;
}

#include <stdio.h>
#include <string.h>

// Typedef token - creating custom type alias
typedef unsigned int uint;
typedef char string[50];

// Enum token - defining enumerated constants
enum Days { MONDAY = 1, TUESDAY, WEDNESDAY, THURSDAY, FRIDAY, SATURDAY, SUNDAY };

// Struct with typedef
typedef struct {
    int id;
    string name;
    float marks;
} Student;

// Global variable (accessible throughout file)
int globalCounter = 0;

void displayStudent(Student s) {
    // Function parameter - local scope
    printf("ID: %d, Name: %s, Marks: %.2f\n", s.id, s.name, s.marks);
}

int main() {
    // Using typedef aliases
    uint positiveNumber = 42;
    string studentName;

    printf("Using typedef uint: %u\n", positiveNumber);

    // Using enum tokens
    enum Days today = WEDNESDAY;
    printf("Today is day number: %d\n", today);

    // Using struct with typedef
    Student s1;
    s1.id = 101;
    strcpy(s1.name, "Rahul Sharma");
    s1.marks = 87.5;

    displayStudent(s1);

    // Demonstrating variable scope
    int localVar = 10;  // Local to main
    {
        int blockVar = 20;  // Block scope
        printf("Block scoped variable: %d\n", blockVar);
        printf("Local variable accessible in block: %d\n", localVar);
    }
    // printf("%d", blockVar); // Error: blockVar not accessible here

    printf("Global variable: %d\n", globalCounter);

    return 0;
}
